1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_BLOCK_SIZE = 3;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	const INSURANCE_VALUES: Record<string, number> = {
16	  sword: 1000,
17	  amulet: 600,
18	  staff: 800,
19	  potion: 400,
20	};
21	
22	const COMPONENT_INSURANCE_VALUE = 250;
23	const DEDUCTIBLE = 100;
24	
25	const FIRST_INSURANCE_RATE = 0.1;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	const LOYALTY_YEARS_THRESHOLD = 2;
28	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
29	const CURSED_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	
33	const isStandardItem = (item: any): boolean => item.type in BASE_PREMIUMS;
34	
35	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
36	
37	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type] ?? 0;
38	
39	function countByType(components: any[]): Record<string, number> {
40	  const counts: Record<string, number> = {};
41	  for (const c of components) {
42	    counts[c.type] = (counts[c.type] ?? 0) + 1;
43	  }
44	  return counts;
45	}
46	
47	function componentGroupPremium(count: number): number {
48	  return count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
49	}
50	
51	function componentPremium(items: any[]): number {
52	  const components = items.filter(isComponent);
53	  const typeCounts = countByType(components);
54	  return Object.values(typeCounts).reduce(
55	    (sum, count) => sum + componentGroupPremium(count),
56	    0,
57	  );
58	}
59	
60	function itemSurcharge(item: any): number {
61	  const base = itemBasePremium(item);
62	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
63	  const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
64	  return cursedSurcharge + enchantmentSurcharge;
65	}
66	
67	function validateItems(items: any[]): void {
68	  for (const item of items) {
69	    if (!isStandardItem(item) && !isComponent(item)) {
70	      throw new Error(`Unknown item type: ${item.type}`);
71	    }
72	  }
73	}
74	
75	function calculateQuotePremium(items: any[], customer: any, quoteIndex: number): number {
76	  validateItems(items);
77	  const standardItems = items.filter((item: any) => !isComponent(item));
78	  const standardBase = standardItems.reduce(
79	    (sum: number, item: any) => sum + itemBasePremium(item),
80	    0,
81	  );
82	  const standardSurcharges = standardItems.reduce(
83	    (sum: number, item: any) => sum + itemSurcharge(item),
84	    0,
85	  );
86	  const componentTotal = componentPremium(items);
87	  const policyBase = standardBase + componentTotal;
88	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
89	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
90	  const followUpDiscount = quoteIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
91	  return Math.ceil(policyBase + standardSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
92	}
93	
94	function itemInsuranceValue(item: any): number {
95	  if (isComponent(item)) return COMPONENT_INSURANCE_VALUE;
96	  return INSURANCE_VALUES[item.type] ?? 0;
97	}
98	
99	function insuranceSum(items: any[]): number {
100	  return items.reduce((sum: number, item: any) => sum + itemInsuranceValue(item), 0);
101	}
102	
103	function processClaim(step: any, policies: Map<number, any>): { payout: number; remainingCap: number } {
104	  const policy = policies.get(step.policy)!;
105	  let totalPayout = 0;
106	  for (const damage of step.incident.damages) {
107	    const reimbursement = damage.amount - DEDUCTIBLE;
108	    totalPayout += Math.max(0, reimbursement);
109	  }
110	  totalPayout = Math.min(totalPayout, policy.remainingCap);
111	  policy.remainingCap -= totalPayout;
112	  return { payout: totalPayout, remainingCap: policy.remainingCap };
113	}
114	
115	export function processScenario(scenario: any): { results: any[] } {
116	  let quoteCount = 0;
117	  const policies = new Map<number, any>();
118	  const results = scenario.steps.map((step: any, index: number) => {
119	    if (step.op === "claim") {
120	      return processClaim(step, policies);
121	    }
122	    const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount);
123	    policies.set(index, { items: step.items, remainingCap: insuranceSum(step.items) * 2 });
124	    quoteCount++;
125	    return { premium };
126	  });
127	  return { results };
128	}
